# Module providing a calculator that works with shapes from models
from models import Shape, Rectangle, Circle

class ShapeCalculator:
    total_area: float

    def __init__(self):
        self.total_area = 0.0

    def add_shape(self, shape: Shape) -> None:
        self.total_area += shape.area()

    def get_total(self) -> float:
        return self.total_area

def compare_shapes(s1: Shape, s2: Shape) -> str:
    if s1.area() > s2.area():
        return s1.name
    else:
        return s2.name
